/**
 * ManHourOverlayPanel
 *
 * Overlay panel showing man-hour workload distribution across depots.
 * Displays weekly utilization with stacked bars and adjustment actions.
 *
 * Features:
 * - Weekly depot workload breakdown (required vs available hours)
 * - Utilization status indicators (overloaded, optimal, underutilized)
 * - Pending adjustments summary
 * - Interactive filtering by depot
 *
 * @see specs/006-user-interface.md Section 6.4.3
 */

import {
  Button,
  ButtonGroup,
  Card,
  Collapse,
  Callout,
  HTMLSelect,
  Icon,
  Intent,
  Spinner,
  Tag,
  Tooltip,
} from '@blueprintjs/core';

import { useOverlay, useFleet, loadManhourOverlayData } from '../../store';
import type { OverlaySliceState, ManhourWeekData, DepotManhourData, ManhourStatus } from '../../store/slices/overlay';
import type { FleetSliceState } from '../../store/slices/fleet';

// =============================================================================
// Constants
// =============================================================================

const LAYOUT = {
  PANEL_WIDTH: 320,
  HEADER_HEIGHT: 48,
  WEEK_ROW_HEIGHT: 36,
  DEPOT_ROW_HEIGHT: 28,
  BAR_HEIGHT: 16,
  COLLAPSED_HEIGHT: 48,
} as const;

const STATUS_COLORS: Record<ManhourStatus, string> = {
  OVERLOADED: '#DC2626',
  OPTIMAL: '#16A34A',
  UNDERUTILIZED: '#CA8A04',
};

const STATUS_INTENTS: Record<ManhourStatus, typeof Intent[keyof typeof Intent]> = {
  OVERLOADED: Intent.DANGER,
  OPTIMAL: Intent.SUCCESS,
  UNDERUTILIZED: Intent.WARNING,
};

// =============================================================================
// Helper Functions
// =============================================================================

function formatWeekDate(dateStr: string): string {
  const date = new Date(dateStr);
  const month = date.toLocaleDateString('en-US', { month: 'short' });
  const day = date.getDate();
  return `${month} ${day}`;
}

function getStatusIcon(status: ManhourStatus): 'warning-sign' | 'tick-circle' | 'info-sign' {
  switch (status) {
    case 'OVERLOADED':
      return 'warning-sign';
    case 'OPTIMAL':
      return 'tick-circle';
    case 'UNDERUTILIZED':
      return 'info-sign';
    default:
      return 'info-sign';
  }
}

function getWorstStatus(depots: DepotManhourData[]): ManhourStatus {
  if (depots.some(d => d.status === 'OVERLOADED')) return 'OVERLOADED';
  if (depots.some(d => d.status === 'UNDERUTILIZED')) return 'UNDERUTILIZED';
  return 'OPTIMAL';
}

// =============================================================================
// Sub-Components
// =============================================================================

interface DepotBarProps {
  depot: DepotManhourData;
}

function DepotBar({ depot }: DepotBarProps) {
  const { depotCode, requiredHours, availableHours, utilizationPct, status, adjustments } = depot;
  const barWidth = Math.min(utilizationPct, 150);
  const hasAdjustments = adjustments.length > 0;

  return (
    <div
      style={{
        display: 'flex',
        alignItems: 'center',
        gap: 8,
        padding: '4px 0',
        borderBottom: '1px solid var(--pt-divider-black)',
      }}
    >
      <div style={{ width: 60, fontSize: 11, fontWeight: 500, color: 'var(--pt-text-color)' }}>
        {depotCode}
      </div>

      <div style={{ flex: 1 }}>
        <Tooltip
          content={
            <div style={{ fontSize: 11 }}>
              <div>Required: {requiredHours.toFixed(0)}h</div>
              <div>Available: {availableHours.toFixed(0)}h</div>
              <div>Utilization: {utilizationPct.toFixed(0)}%</div>
              {hasAdjustments && (
                <div style={{ marginTop: 4, borderTop: '1px solid rgba(255,255,255,0.2)', paddingTop: 4 }}>
                  Pending adjustments: {adjustments.length}
                </div>
              )}
            </div>
          }
          position="top"
        >
          <div style={{ position: 'relative', height: LAYOUT.BAR_HEIGHT, backgroundColor: 'var(--pt-divider-black)', borderRadius: 3 }}>
            <div
              style={{
                position: 'absolute',
                left: 0,
                top: 0,
                height: '100%',
                width: `${barWidth}%`,
                backgroundColor: STATUS_COLORS[status],
                borderRadius: 3,
                transition: 'width 0.2s ease',
              }}
            />
            {utilizationPct > 100 && (
              <div
                style={{
                  position: 'absolute',
                  left: '100%',
                  top: '50%',
                  transform: 'translate(-50%, -50%)',
                  fontSize: 9,
                  fontWeight: 700,
                  color: STATUS_COLORS.OVERLOADED,
                }}
              >
                !
              </div>
            )}
          </div>
        </Tooltip>
      </div>

      <div style={{ width: 50, textAlign: 'right', fontSize: 10, fontFamily: 'monospace', color: 'var(--pt-text-muted)' }}>
        {utilizationPct.toFixed(0)}%
      </div>

      {hasAdjustments && (
        <Tag minimal intent={Intent.PRIMARY} style={{ fontSize: 9 }}>
          {adjustments.length}
        </Tag>
      )}
    </div>
  );
}

interface WeekRowProps {
  week: ManhourWeekData;
  isExpanded: boolean;
  onToggle: () => void;
  depotFilter: string | null;
}

function WeekRow({ week, isExpanded, onToggle, depotFilter }: WeekRowProps) {
  const filteredDepots = depotFilter
    ? week.depots.filter(d => d.depotId === depotFilter)
    : week.depots;

  const worstStatus = getWorstStatus(filteredDepots);
  const totalRequired = filteredDepots.reduce((sum, d) => sum + d.requiredHours, 0);
  const totalAvailable = filteredDepots.reduce((sum, d) => sum + d.availableHours, 0);
  const pendingAdjustments = filteredDepots.reduce((sum, d) => sum + d.adjustments.length, 0);

  return (
    <div style={{ marginBottom: 4 }}>
      <div
        onClick={onToggle}
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: 8,
          padding: '8px 12px',
          backgroundColor: isExpanded ? 'var(--pt-intent-primary-5)' : 'var(--pt-app-background-color)',
          borderRadius: 4,
          cursor: 'pointer',
          transition: 'background-color 0.15s ease',
        }}
      >
        <Icon
          icon={isExpanded ? 'chevron-down' : 'chevron-right'}
          size={12}
          color="var(--pt-text-muted)"
        />

        <Icon
          icon={getStatusIcon(worstStatus)}
          size={14}
          intent={STATUS_INTENTS[worstStatus]}
        />

        <div style={{ flex: 1 }}>
          <div style={{ fontSize: 12, fontWeight: 600 }}>
            Week of {formatWeekDate(week.weekStart)}
          </div>
          <div style={{ fontSize: 10, color: 'var(--pt-text-muted)' }}>
            {totalRequired.toFixed(0)}h / {totalAvailable.toFixed(0)}h available
          </div>
        </div>

        {pendingAdjustments > 0 && (
          <Tag minimal intent={Intent.PRIMARY} round style={{ fontSize: 10 }}>
            {pendingAdjustments} adjustments
          </Tag>
        )}
      </div>

      <Collapse isOpen={isExpanded}>
        <div style={{ padding: '8px 12px 12px 28px' }}>
          {filteredDepots.map(depot => (
            <DepotBar key={depot.depotId} depot={depot} />
          ))}
        </div>
      </Collapse>
    </div>
  );
}

