export interface ManHourOverlayPanelProps {
  onClose?: () => void;
}

export function ManHourOverlayPanel({ onClose }: ManHourOverlayPanelProps) {
  const { state: overlayStateRaw, actions: overlayActions } = useOverlay();
  const { state: fleetStateRaw } = useFleet();

  const overlayState = overlayStateRaw as unknown as OverlaySliceState;
  const fleetState = fleetStateRaw as unknown as FleetSliceState;

  const {
    manhourData,
    manhourLoading,
    manhourError,
    manhourWeeks,
    manhourDepotFilter,
    manhourExpandedWeeks,
    manhourPanelExpanded,
  } = overlayState;

  const depots = fleetState.depots || [];

  const handleLoadData = () => {
    loadManhourOverlayData(overlayActions, {
      weeks: manhourWeeks,
      depotId: manhourDepotFilter ?? undefined,
    });
  };

  const handleWeeksChange = (event: React.ChangeEvent<HTMLSelectElement>) => {
    overlayActions.setManhourWeeks(Number(event.target.value));
  };

  const handleDepotChange = (event: React.ChangeEvent<HTMLSelectElement>) => {
    const value = event.target.value;
    overlayActions.setManhourDepotFilter(value || null);
  };

  const handleToggleWeek = (weekStart: string) => {
    overlayActions.toggleManhourWeek(weekStart);
  };

  // Calculate summary stats
  const totalOverloadedWeeks = manhourData?.weeks.filter(w =>
    w.depots.some(d => d.status === 'OVERLOADED')
  ).length ?? 0;

  const totalOverloadedHours = manhourData?.weeks.reduce((total, week) => {
    return total + week.depots.reduce((weekTotal, depot) => {
      if (depot.status === 'OVERLOADED') {
        return weekTotal + (depot.requiredHours - depot.availableHours);
      }
      return weekTotal;
    }, 0);
  }, 0) ?? 0;

  return (
    <Card
      elevation={2}
      style={{
        position: 'absolute',
        top: 60,
        right: 12,
        width: LAYOUT.PANEL_WIDTH,
        maxHeight: manhourPanelExpanded ? 'calc(100vh - 140px)' : LAYOUT.COLLAPSED_HEIGHT,
        overflow: 'hidden',
        transition: 'max-height 0.2s ease',
        zIndex: 20,
      }}
    >
      {/* Header */}
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: 8,
          padding: '12px 16px',
          borderBottom: manhourPanelExpanded ? '1px solid var(--pt-divider-black)' : 'none',
          cursor: 'pointer',
        }}
        onClick={() => overlayActions.toggleManhourPanel()}
      >
        <Icon icon="chart" size={16} intent={Intent.PRIMARY} />
        <div style={{ flex: 1 }}>
          <div style={{ fontSize: 14, fontWeight: 600 }}>Man-Hour Workload</div>
          {manhourData && !manhourPanelExpanded && (
            <div style={{ fontSize: 10, color: 'var(--pt-text-muted)' }}>
              {totalOverloadedWeeks} overloaded weeks
            </div>
          )}
        </div>
        <Icon
          icon={manhourPanelExpanded ? 'chevron-up' : 'chevron-down'}
          size={14}
          color="var(--pt-text-muted)"
        />
        {onClose && (
          <Button
            minimal
            small
            icon="cross"
            onClick={(e) => {
              e.stopPropagation();
              onClose();
            }}
          />
        )}
      </div>

      {manhourPanelExpanded && (
        <>
          {/* Controls */}
          <div style={{ padding: '12px 16px', borderBottom: '1px solid var(--pt-divider-black)' }}>
            <div style={{ display: 'flex', gap: 8, marginBottom: 8 }}>
              <HTMLSelect
                value={manhourWeeks}
                onChange={handleWeeksChange}
                style={{ flex: 1 }}
                minimal
              >
                <option value={4}>4 weeks</option>
                <option value={8}>8 weeks</option>
                <option value={12}>12 weeks</option>
                <option value={26}>26 weeks</option>
              </HTMLSelect>

              <HTMLSelect
                value={manhourDepotFilter || ''}
                onChange={handleDepotChange}
                style={{ flex: 1 }}
                minimal
              >
                <option value="">All depots</option>
                {depots.map(depot => (
                  <option key={depot.id} value={depot.id}>
                    {depot.code}
                  </option>
                ))}
              </HTMLSelect>
            </div>

            <ButtonGroup fill>
              <Button
                intent={Intent.PRIMARY}
                icon="refresh"
                onClick={handleLoadData}
                loading={manhourLoading}
              >
                {manhourData ? 'Refresh' : 'Load Data'}
              </Button>
            </ButtonGroup>
          </div>

          {/* Content */}
          <div style={{ padding: '12px 16px', overflow: 'auto', maxHeight: 'calc(100vh - 340px)' }}>
            {manhourLoading && !manhourData && (
              <div style={{ textAlign: 'center', padding: 24 }}>
                <Spinner size={32} />
                <div style={{ marginTop: 8, color: 'var(--pt-text-muted)' }}>
                  Loading workload data...
                </div>
              </div>
            )}

            {manhourError && (
              <Callout intent={Intent.DANGER} icon="error">
                {manhourError}
              </Callout>
            )}

            {!manhourLoading && !manhourError && !manhourData && (
              <div style={{ textAlign: 'center', padding: 24, color: 'var(--pt-text-muted)' }}>
                <Icon icon="chart" size={32} style={{ marginBottom: 8, opacity: 0.5 }} />
                <div>Click "Load Data" to view workload</div>
              </div>
            )}

            {manhourData && (
              <>
                {/* Summary */}
                {totalOverloadedWeeks > 0 && (
                  <Callout intent={Intent.WARNING} icon="warning-sign" style={{ marginBottom: 12 }}>
                    <strong>{totalOverloadedWeeks} week{totalOverloadedWeeks > 1 ? 's' : ''}</strong> with resource constraints
                    <div style={{ fontSize: 11, marginTop: 4 }}>
                      {totalOverloadedHours.toFixed(0)} hours over capacity
                    </div>
                  </Callout>
                )}

                {/* Weeks */}
                {manhourData.weeks.map(week => (
                  <WeekRow
                    key={week.weekStart}
                    week={week}
                    isExpanded={manhourExpandedWeeks.includes(week.weekStart)}
                    onToggle={() => handleToggleWeek(week.weekStart)}
                    depotFilter={manhourDepotFilter}
                  />
                ))}

                {manhourData.weeks.length === 0 && (
                  <div style={{ textAlign: 'center', padding: 24, color: 'var(--pt-text-muted)' }}>
                    No projections available for selected period
                  </div>
                )}
              </>
            )}
          </div>

          {/* Legend */}
          <div
            style={{
              display: 'flex',
              justifyContent: 'center',
              gap: 16,
              padding: '8px 16px',
              borderTop: '1px solid var(--pt-divider-black)',
              fontSize: 10,
            }}
          >
            <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
              <div style={{ width: 8, height: 8, borderRadius: 2, backgroundColor: STATUS_COLORS.OVERLOADED }} />
              <span>Overloaded</span>
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
              <div style={{ width: 8, height: 8, borderRadius: 2, backgroundColor: STATUS_COLORS.OPTIMAL }} />
              <span>Optimal</span>
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
              <div style={{ width: 8, height: 8, borderRadius: 2, backgroundColor: STATUS_COLORS.UNDERUTILIZED }} />
              <span>Under</span>
            </div>
          </div>
        </>
      )}
    </Card>
  );
}

