    70→  const target = event.target as HTMLElement;
    71→  const tagName = target.tagName.toLowerCase();
    72→
    73→  // Disable shortcuts in input elements
    74→  if (tagName === 'input' || tagName === 'textarea' || tagName === 'select') {
    75→    return true;
    76→  }
    77→
    78→  // Disable shortcuts in contenteditable elements
    79→  if (target.isContentEditable) {
    80→    return true;
    81→  }
    82→
    83→  // Check for BlueprintJS editable text
    84→  if (target.classList.contains('bp5-editable-text-content')) {
    85→    return true;
    86→  }
    87→
    88→  return false;
