    92→ * Handle keyboard events for the canvas
    93→ *
    94→ * @param event - The keyboard event
    95→ * @param callbacks - Handler callbacks
    96→ * @returns true if the event was handled, false otherwise
    97→ */
    98→export function handleCanvasKeyDown(
    99→  event: KeyboardEvent,
   100→  callbacks: KeyboardHandlerCallbacks
   101→): boolean {
   102→  // Skip if typing in an input
   103→  if (isInputElement(event)) {
   104→    return false;
   105→  }
   106→
   107→  // Skip if shortcuts are disabled (except for ?)
   108→  if (!callbacks.isShortcutsEnabled() && event.key !== '?') {
   109→    return false;
   110→  }
   111→
   112→  const { key, shiftKey, ctrlKey, metaKey, altKey } = event;
   113→
   114→  // Normalize key for cross-platform compatibility
   115→  const normalizedKey = key.toLowerCase();
   116→
   117→  // Handle Escape key (always works, even during drag)
   118→  if (key === 'Escape') {
   119→    event.preventDefault();
   120→
   121→    if (callbacks.isDragging()) {
   122→      // Cancel drag handled by drag system
   123→      return true;
   124→    }
   125→
   126→    if (callbacks.hasOpenDialog()) {
   127→      callbacks.onCloseDialog();
   128→      return true;
   129→    }
   130→
   131→    // Clear selection
   132→    callbacks.onClearSelection();
   133→    return true;
   134→  }
   135→
   136→  // Don't process other shortcuts during drag or with open dialog
   137→  if (callbacks.isDragging() || callbacks.hasOpenDialog()) {
   138→    return false;
   139→  }
   140→
   141→  // Handle ? for keyboard shortcuts help
   142→  if (key === '?' || (shiftKey && key === '/')) {
   143→    event.preventDefault();
   144→    callbacks.onShowKeyboardHelp();
   145→    return true;
   146→  }
   147→
   148→  // Handle modifier key combinations first
   149→  // Most canvas shortcuts shouldn't use modifiers
   150→  if (ctrlKey || metaKey || altKey) {
   151→    // Allow Ctrl/Cmd shortcuts to pass through for browser defaults
   152→    return false;
   153→  }
   154→
   155→  // Arrow keys - Pan canvas
   156→  if (key === 'ArrowUp' || key === 'ArrowDown' || key === 'ArrowLeft' || key === 'ArrowRight') {
   157→    event.preventDefault();
   158→    const amount = shiftKey ? DEFAULT_PAN_AMOUNT * 3 : DEFAULT_PAN_AMOUNT;
   159→
   160→    switch (key) {
   161→      case 'ArrowUp':
   162→        callbacks.onPan('up', amount);
   163→        break;
   164→      case 'ArrowDown':
   165→        callbacks.onPan('down', amount);
   166→        break;
   167→      case 'ArrowLeft':
   168→        callbacks.onPan('left', amount);
   169→        break;
   170→      case 'ArrowRight':
   171→        callbacks.onPan('right', amount);
   172→        break;
   173→    }
   174→    return true;
   175→  }
   176→
   177→  // Home key - Go to today
   178→  if (key === 'Home') {
   179→    event.preventDefault();
   180→    callbacks.onGoToToday();
   181→    return true;
   182→  }
   183→
   184→  // + key - Zoom in (also = key without shift on most keyboards)
   185→  if (key === '+' || key === '=' || (shiftKey && key === '=')) {
   186→    event.preventDefault();
   187→    callbacks.onZoomIn();
   188→    return true;
   189→  }
   190→
   191→  // - key - Zoom out
   192→  if (key === '-') {
   193→    event.preventDefault();
   194→    callbacks.onZoomOut();
   195→    return true;
   196→  }
   197→
   198→  // Number keys 1-5 - Switch zoom levels
   199→  if (ZOOM_LEVEL_MAP[key]) {
   200→    event.preventDefault();
   201→    callbacks.onSetZoomLevel(ZOOM_LEVEL_MAP[key]);
   202→    return true;
   203→  }
   204→
   205→  // Single letter shortcuts (case insensitive)
   206→  switch (normalizedKey) {
   207→    // t - Go to today
   208→    case 't':
   209→      event.preventDefault();
   210→      callbacks.onGoToToday();
   211→      return true;
   212→
   213→    // s - Strategic view
   214→    case 's':
   215→      event.preventDefault();
   216→      callbacks.onSetZoomLevel('STRATEGIC');
   217→      return true;
   218→
   219→    // o - Operational view
   220→    case 'o':
   221→      event.preventDefault();
   222→      callbacks.onSetZoomLevel('OPERATIONAL');
   223→      return true;
   224→
   225→    // l - Lock/unlock selected PM
   226→    case 'l':
   227→      if (callbacks.getSelectedPmId()) {
   228→        event.preventDefault();
   229→        callbacks.onToggleLock();
   230→        return true;
   231→      }
   232→      break;
   233→
   234→    // Space - Toggle selection
   235→    case ' ':
   236→      event.preventDefault();
   237→      callbacks.onToggleSelection();
   238→      return true;
   239→  }
   240→
   241→  // Enter - Activate selected element
   242→  if (key === 'Enter') {
   243→    event.preventDefault();
   244→    callbacks.onActivateSelected();
   245→    return true;
   246→  }
   247→
   248→  // Delete/Backspace - Delete selected PM (with confirmation)
   249→  if (key === 'Delete' || key === 'Backspace') {
   250→    if (callbacks.getSelectedPmId()) {
   251→      event.preventDefault();
   252→      callbacks.onDeleteSelected();
   253→      return true;
   254→    }
   255→  }
   256→
   257→  return false;
   258→}
   259→
   260→/**
   261→ * Create a keyboard event handler bound to callbacks
   262→ *
   263→ * @param callbacks - Handler callbacks
   264→ * @returns Event handler function
   265→ */
   266→export function createCanvasKeyboardHandler(
   267→  callbacks: KeyboardHandlerCallbacks
   268→): (event: React.KeyboardEvent) => void {
   269→  return (event: React.KeyboardEvent) => {
   270→    const handled = handleCanvasKeyDown(event.nativeEvent, callbacks);
   271→    if (handled) {
   272→      event.stopPropagation();
   273→    }
   274→  };
   275→}
