  1161→        >
  1162→          <div style={{ marginTop: '16px', fontSize: '12px', color: 'var(--pt-text-muted)' }}>
  1163→            <p>Shows PM schedule from {detailFromDate} to {detailToDate}</p>
  1164→            <ul style={{ textAlign: 'left', maxWidth: '300px', margin: '8px auto' }}>
  1165→              <li>Full PM editing interface</li>
