        <NonIdealState
          icon={<Spinner size={48} />}
          title="Loading detail view..."
          description="Fetching detailed PM data with history"
        />
      );
    }

    if (detailError) {
      return (
        <NonIdealState
          icon="error"
          title="Error loading detail view"
          description={detailError}
          action={
            <Button intent="primary" onClick={handleLoadDetailData}>
              Retry
            </Button>
          }
        />
      );
    }

    if (!detailData) {
      return (
        <NonIdealState
          icon="document"
          title="Detail View"
          description="Load 1-week PM schedule with full editing capabilities"
          action={
            <ButtonGroup>
              <Button intent="primary" onClick={handleLoadDetailData}>
                Load Detail Data
              </Button>
            </ButtonGroup>
          }
        >
          <div style={{ marginTop: '16px', fontSize: '12px', color: 'var(--pt-text-muted)' }}>
            <p>Shows PM schedule from {detailFromDate} to {detailToDate}</p>
            <ul style={{ textAlign: 'left', maxWidth: '300px', margin: '8px auto' }}>
              <li>Full PM editing interface</li>
              <li>Constraint validation feedback</li>
              <li>Material availability status</li>
              <li>Change history timeline</li>
            </ul>
          </div>
        </NonIdealState>
      );
    }

    return (
      <DetailCardOverlay
        data={detailData}
        fromDate={new Date(detailFromDate)}
        toDate={new Date(detailToDate)}
        width={DEFAULT_CANVAS_WIDTH}
        height={DEFAULT_CANVAS_HEIGHT}
        selectedPmIds={canvasState.selection.selectedPmIds}
        expandedPmIds={detailExpandedPmIds}
        onPmSelect={handleDetailPmSelect}
        onPmExpand={handleDetailPmExpand}
        onPmCollapse={handleDetailPmCollapse}
        onPmEdit={handleDetailPmEdit}
        onPmLock={handleDetailPmLock}
        onPmUnlock={handleDetailPmUnlock}
        onViewHistory={handleDetailViewHistory}
      />
    );
  };

  // Handle focus events to detect keyboard vs mouse navigation
  const handleFocus = () => {
    // Focus visible only if triggered by keyboard
    if (isKeyboardNavigationRef.current) {
      uiActions.setFocusVisible(true);
    }
  };

  const handleBlur = () => {
    // Reset keyboard navigation flag on blur
    isKeyboardNavigationRef.current = false;
    uiActions.setFocusVisible(false);
  };

  const handleMouseDownForA11y = (event: React.MouseEvent) => {
    // Mouse click resets keyboard navigation mode
    isKeyboardNavigationRef.current = false;
    uiActions.setFocusVisible(false);
    // Call original handler
    handleMouseDown(event);
  };

  const handleKeyDownForA11y = (event: React.KeyboardEvent) => {
    // Tab key indicates keyboard navigation
    if (event.key === 'Tab') {
      isKeyboardNavigationRef.current = true;
    }
    // Call original handler
    handleKeyDown(event);
  };

  // Calculate visible focus ring style
  const focusRingStyle: React.CSSProperties = focusVisible ? {
    outline: FOCUS_RING_STYLES.default.outline,
    outlineOffset: FOCUS_RING_STYLES.default.outlineOffset,
    boxShadow: FOCUS_RING_STYLES.default.boxShadow,
  } : {
    outline: 'none',
  };

  // Calculate transition style (respects reduced motion)
  const transitionStyle = isPanning || reducedMotion ? 'none' : 'transform 0.1s ease-out';

  // Generate ARIA description
  const ariaDescription = `PM schedule canvas showing ${zoomLevel.replace('_', ' ')} view from ${viewport.startDate} to ${viewport.endDate}. ${viewport.trainIds.length || 'All'} trains visible. Use arrow keys to pan, plus/minus to zoom, 1-5 to switch views. Press question mark for full keyboard shortcuts help.`;

  return (
    <div
      ref={containerRef}
      className="mms-canvas"
      tabIndex={0}
      // ARIA attributes for accessibility (WCAG 2.1 AA)
      role="application"
      aria-label="PM Schedule Canvas"
      aria-description={ariaDescription}
      aria-roledescription="Interactive PM scheduling canvas"
      aria-busy={strategicLoading || tacticalLoading || operationalLoading || detailLoading}
      style={{
        flex: 1,
        position: 'relative',
        overflow: 'hidden',
        backgroundColor: 'var(--pt-app-background-color, #f5f8fa)',
        cursor: isPanning ? 'grabbing' : 'grab',
        ...focusRingStyle,
      }}
      onWheel={handleWheel}
      onMouseDown={handleMouseDownForA11y}
      onMouseUp={handleMouseUp}
      onMouseLeave={handleMouseUp}
      onMouseMove={handleMouseMove}
      onKeyDown={handleKeyDownForA11y}
      onFocus={handleFocus}
      onBlur={handleBlur}
    >
      {/* Hidden screen reader status region for canvas state */}
      <div
        role="status"
        aria-live="polite"
        aria-atomic="true"
        className="sr-only"
        style={{
          position: 'absolute',
          width: '1px',
          height: '1px',
          padding: 0,
          margin: '-1px',
          overflow: 'hidden',
          clip: 'rect(0, 0, 0, 0)',
          whiteSpace: 'nowrap',
          border: 0,
        }}
      >
        {`Zoom: ${zoomLevel.replace('_', ' ')}. Viewing ${viewport.startDate} to ${viewport.endDate}.`}
      </div>

      <div
        style={{
          position: 'absolute',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          transform: `translate(${-canvasState.panX}px, ${-canvasState.panY}px)`,
          transition: transitionStyle,
        }}
      >
        {renderContent()}
      </div>

      <div style={{
        position: 'absolute',
        top: '12px',
        right: '12px',
        zIndex: 10,
      }}>
        <Card elevation={1} style={{ padding: '8px 12px' }}>
          <div style={{ fontSize: '11px', color: 'var(--pt-text-muted)', marginBottom: '4px' }}>
            Zoom Level
          </div>
          <div style={{ fontSize: '14px', fontWeight: 600 }}>
            {zoomLevel.replace('_', ' ')}
          </div>
          <div style={{ fontSize: '11px', fontFamily: 'monospace' }}>
            {zoom.toFixed(1)} / 20
          </div>
        </Card>
      </div>

      <div style={{
        position: 'absolute',
        bottom: '12px',
        left: '12px',
        zIndex: 10,
      }}>
        <Card elevation={1} style={{ padding: '8px 12px' }}>
          <div style={{ fontSize: '11px' }}>
            <span style={{ color: 'var(--pt-text-muted)' }}>Viewport: </span>
            <span style={{ fontFamily: 'monospace' }}>
              {viewport.startDate} to {viewport.endDate}
            </span>
          </div>
          <div style={{ fontSize: '11px' }}>
            <span style={{ color: 'var(--pt-text-muted)' }}>Trains: </span>
            <span>{viewport.trainIds.length || 'All'}</span>
          </div>
        </Card>
      </div>

      {(canvasState.layers.manhourOverlay || canvasState.layers.driftOverlay || canvasState.layers.baselineShadow) && (
        <div style={{
          position: 'absolute',
          top: '12px',
          left: '12px',
          zIndex: 10,
          display: 'flex',
          gap: '4px',
        }}>
          {canvasState.layers.manhourOverlay && (
            <Tag intent="primary" icon="chart">Man-hours</Tag>
          )}
          {canvasState.layers.driftOverlay && (
            <Tag intent="warning" icon="delta">Drift</Tag>
          )}
          {canvasState.layers.baselineShadow && (
            <Tag
              minimal
              icon={overlayState.baselineShadowLoading ? 'time' : 'git-commit'}
              intent={overlayState.baselineShadowError ? 'danger' : 'none'}
              title={overlayState.baselineShadowData
                ? `${overlayState.baselineShadowData.summary.movedPms} moved, ${overlayState.baselineShadowData.summary.addedPms} added, ${overlayState.baselineShadowData.summary.removedPms} removed`
                : overlayState.baselineShadowError || 'Loading...'}
            >
              {overlayState.baselineShadowLoading ? 'Loading...' : 'Baseline'}
            </Tag>
          )}
        </div>
      )}

      {/* Drag Confirmation Dialog */}
      <DragConfirmationDialog
        isOpen={dragConfirmRef.current.isOpen}
        pmCode={dragConfirmRef.current.pmCode}
        trainNumber={dragConfirmRef.current.trainNumber}
        sourceDate={dragConfirmRef.current.sourceDate}
        targetDate={dragConfirmRef.current.targetDate}
        impact={dragConfirmRef.current.impact}
        violations={pmState.drag.constraintViolations}
        isLoading={dragConfirmRef.current.isLoadingImpact}
        onConfirm={handleDragConfirm}
        onCancel={handleDragCancel}
      />

      {/* Keyboard Shortcuts Dialog */}
      <KeyboardShortcutsDialog />

      {/* Keyboard shortcut hint in corner */}
      <div style={{
        position: 'absolute',
        bottom: '12px',
        right: '12px',
        zIndex: 10,
        fontSize: '11px',
        color: 'var(--pt-text-muted)',
        opacity: 0.7,
      }}>
        Press <kbd style={{
          padding: '2px 6px',
          backgroundColor: 'rgba(0,0,0,0.1)',
          borderRadius: '3px',
          fontFamily: 'monospace',
          fontSize: '10px',
        }}>?</kbd> for keyboard shortcuts
      </div>
    </div>
  );
}
